gfY(){return"\u03a4\u03c5\u03c0\u03b9\u03ba\u03cc\u03c2 \u03a1\u03c5\u03b8\u03bc\u03cc\u03c2 \u039c\u03b5\u03c4\u03b1\u03c6\u03bf\u03c1\u03ac\u03c2 \u039f\u03be\u03c5\u03b3\u03cc\u03bd\u03bf\u03c5 \u03b3\u03b9\u03b1 \u0391\u03b5\u03c1\u03b9\u03c3\u03c4\u03ae\u03c1\u03b1 1 \u03c3\u03b5 kg O\u2082/\u03ce\u03c1\u03b1 \u03b1\u03bd\u03ac \u03b1\u03b5\u03c1\u03b9\u03c3\u03c4\u03ae\u03c1\u03b1"},
