gff(){return"\u03a4\u03b5\u03bb\u03b9\u03ba\u03ae \u03c3\u03c5\u03b3\u03ba\u03ad\u03bd\u03c4\u03c1\u03c9\u03c3\u03b7 \u03bf\u03be\u03c5\u03b3\u03cc\u03bd\u03bf\u03c5 \u03c3\u03c4\u03b7 \u03c3\u03c4\u03ae\u03bb\u03b7 \u03bd\u03b5\u03c1\u03bf\u03cd \u03c3\u03b5 mg/L"},
