gi3(){return"\u03a3\u03cd\u03c3\u03c4\u03b1\u03c3\u03b7: \u039a\u03b1\u03b9 \u03bf\u03b9 \u03b4\u03cd\u03bf \u03b1\u03b5\u03c1\u03b9\u03c3\u03c4\u03ae\u03c1\u03b5\u03c2 \u03ad\u03c7\u03bf\u03c5\u03bd \u03b9\u03c3\u03bf\u03b4\u03cd\u03bd\u03b1\u03bc\u03bf \u03b5\u03c4\u03ae\u03c3\u03b9\u03bf \u03ba\u03cc\u03c3\u03c4\u03bf\u03c2."},
